  <Stack direction="column" gap="400">
    <Stack direction="row" gap="300" align="center">
      <Icon as={Icons.Info} color="primary.11" size="lg" />
      <Icon as={Icons.CheckCircle} color="positive.11" size="lg" />
      <Icon as={Icons.Warning} color="warning.11" size="lg" />
      <Icon as={Icons.Error} color="critical.11" size="lg" />
      <Icon as={Icons.Help} color="info.11" size="lg" />
    </Stack>

    <Stack direction="row" gap="300" align="center">
      <Icon as={Icons.Favorite} color="deeppink" size="lg" />
      <Icon as={Icons.Star} color="gold" size="lg" />
      <Icon as={Icons.Palette} color="rebeccapurple" size="lg" />
    </Stack>
  </Stack>
)
```

### Using the `as` prop

The `as` prop provides a convenient shorthand for rendering an icon without nesting:

```jsx live-dev
const App = () => {
  const [iconType, setIconType] = React.useState<IconProps["as"]>(Icons.Home);

  return (
    <Stack direction="column" gap="400">
      <Stack direction="row" gap="200">
        <Button size="xs" onClick={() => setIconType(Icons.Home)}>Home</Button>
        <Button size="xs" onClick={() => setIconType(Icons.Settings)}>Settings</Button>
        <Button size="xs" onClick={() => setIconType(Icons.Notifications)}>Notifications</Button>
        <Button size="xs" onClick={() => setIconType(Icons.AccountCircle)}>Account</Button>
      </Stack>

      <Stack direction="row" gap="300" align="center">
        <Icon as={iconType} size="xl" color="primary.11" />
        <Text>Selected icon changes dynamically</Text>
      </Stack>
    </Stack>
  );
}
```

